    newUntil: number;
    section: "newsEntries" | "esportNewsEntries" | "communityEntries";
    thumbnail: ImageSourceSets;
    thumbnailAlt: ImageSourceSets;
    title: string;
    url: string;
};

export const ImageArticle = (props: ImageArticleType) => {
    const [ref, isVisible] = useElementAppearsOnScreen<HTMLDivElement>();
    const { trackImpression } = useSnowplowContext();

    React.useEffect(() => {
        if (isVisible) {
            trackImpression(props.id, props.title);
        }
    }, [props.id, isVisible]);

    return (
        <div ref={ref} className="article-image">
            <Regular {...props} external={true} ctaHidden={!props.url} />
        </div>
    );
};
